commonMistakes.wrongCode:
.card::before {
  background: red;
  width: 20px;
  height: 20px;
  /* No content property - nothing renders! */
}

commonMistakes.correctCode:
.card::before {
  content: '';  /* Even an empty string works */
  background: red;
  width: 20px;
  height: 20px;
  display: block;
}

commonMistakes.wrongCode:
/* Wanted every 3rd row, starting from the first */
tr:nth-child(3n) {
  background: #f1f5f9;
}
/* This selects the 3rd, 6th, 9th... - NOT the 1st, 4th, 7th! */

.card:before {
  content: 'NEW';
}
/* This works but is the old syntax */

commonMistakes.correctCode:
.card::before {
  content: 'NEW';
}
/* Modern CSS3 syntax - use this */

commonMistakes.wrongCode:
button:hover {
  background: purple;
  outline: 2px solid cyan;
}
/* Keyboard users see no feedback! */

commonMistakes.correctCode:
button:hover,
button:focus-visible {
  background: purple;
  outline: 2px solid cyan;
}

